@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix cdif: <https://cdif.org/0.1/> .
@prefix cdifd: <https://cdif.org/validation/0.1/shacl#> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xas: <https://xas.org/dictionary/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode xas:monochromatorEnergy ;
            sh:resultMessage "cdi:qualifies @id should reference the @id of another variableMeasured instance variable defined for the same dataset." ;
            sh:resultPath cdi:qualifies ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraint [ a sh:SPARQLConstraint ;
                    sh:message "cdi:qualifies @id should reference the @id of another variableMeasured instance variable defined for the same dataset." ;
                    sh:prefixes ( [ sh:namespace "http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/" ;
                                sh:prefix "cdi" ] [ sh:namespace "https://cdif.org/0.1/" ;
                                sh:prefix "cdif" ] [ sh:namespace "http://schema.org/" ;
                                sh:prefix "schema" ] ) ;
                    sh:select """
            PREFIX cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/>
            PREFIX cdif: <https://cdif.org/0.1/>
            PREFIX schema: <http://schema.org/>
            SELECT $this (cdi:qualifies AS ?path) (?target AS ?value)
            WHERE {
                $this cdi:qualifies ?target .
                FILTER NOT EXISTS {
                    ?dataset schema:variableMeasured ?target .
                    ?dataset schema:variableMeasured $this .
                }
            }""" ;
                    sh:severity sh:Warning ] ;
            sh:sourceConstraintComponent sh:SPARQLConstraintComponent ;
            sh:sourceShape cdifd:QualifiesRequiredForAttributeShape ;
            sh:value <https://example.org/temperatureVariable> ],
        [ a sh:ValidationResult ;
            sh:focusNode xas:monochromatorEnergy ;
            sh:resultMessage "for cdi InstanceVariable a physical data type should be provided." ;
            sh:resultPath cdif:physicalDataType ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:OrConstraintComponent ;
            sh:sourceShape [ sh:message "for cdi InstanceVariable a physical data type should be provided." ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ;
                                sh:minLength 5 ] [ sh:class schema1:DefinedTerm ;
                                sh:property [ sh:message "a defined term should have an identifier that is a resolvable URI" ;
                                        sh:minCount 1 ;
                                        sh:or ( [ ] [ ] ) ;
                                        sh:path schema1:identifier ] ] ) ;
                    sh:path cdif:physicalDataType ;
                    sh:severity sh:Warning ] ;
            sh:value [ a cdi:ControlledVocabularyEntry ;
                    cdi:entryValue "xsd:decimal" ] ] .

